SELECT invoice_number
FROM invoices
ORDER BY invoice_number;

SELECT invoice_number
FROM invoices
ORDER BY invoice_number ASC;

SELECT SUM(amount) AS total_unpaid_amount
FROM invoices
WHERE status = 'Unpaid';

SELECT invoice_number
FROM invoices
ORDER BY invoice_number;

SELECT DISTINCT invoice_number
FROM invoices
WHERE status = 'Paid';
